module RefModule(clk, rst, load, data_in, Q);
    input clk, rst, load;
    input [7:0] data_in;
    output reg [7:0] Q;

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        if (rst)
            Q <= 8'b00000000;
        else if (load)
            Q <= data_in;
        else
            Q <= {Q[6:0], 1'b0};
    end
endmodule
